  {"type":"cloze","sentence":"Models can be ___ via repeated queries.","a":"extracted","alts":["extracted"],"explain":"PP"},
  {"type":"word_form","base":"PERTURB","sentence":"Imperceptible ___ change the classifier output.","a":"perturbations","alts":["perturbations"],"explain":"-ation"},
  {"type":"word_form","base":"POISON","sentence":"___ samples are injected at training time.","a":"Poisoned","alts":["Poisoned"],"explain":"-ed"},
  {"type":"word_form","base":"ADVERSARY","sentence":"An ___ mindset is required.","a":"adversarial","alts":["adversarial"],"explain":"-ial"},
  {"type":"word_form","base":"PROVENANCE","sentence":"Trained-data ___ pipelines are essential.","a":"provenance","alts":["provenance"],"explain":"-ance"},
  {"type":"word_form","base":"EVADE","sentence":"___ samples slip past defences.","a":"Evasion","alts":["Evasion"],"explain":"-ion"},
