  {"type":"mc_cloze","sentence":"___ vendors promise turnkey migration, reality is harder.","options":["Although","Despite","Much as","Even"],"a":2,"explain":"MUCH AS"},
  {"type":"mc_cloze","sentence":"Hardly had they begun ___ dependencies multiplied.","options":["than","when","while","then"],"a":1,"explain":"hardly … when"},
  {"type":"mc_cloze","sentence":"Notwithstanding these obstacles, the migration ___ happening.","options":["is","are","was","were"],"a":0,"explain":"sing"},
