# ---- MERGE ----
path = Path(r"E:\CLAUDE\PAOLO BACA MANRIQUE\course-app\course_data.json")
course = json.loads(path.read_text(encoding="utf-8"))

added_new = 0; extended = 0
for level in course["levels"]:
    if level["code"] != "C1":
        continue
    for lesson in level["lessons"]:
        n = lesson["n"]
        if n in NEW and not lesson.get("has_content"):
            entry = NEW[n]
            if entry.get("notes"): lesson["lesson_notes"] = entry["notes"]
            if entry.get("passage"):
                p = entry["passage"]
                lesson["passage"] = {
                    "title": p.get("title", lesson["topic"]),
                    "text": p["text"],
                    "word_count": p.get("wc", len(p["text"].split())),
                    "source": p["source"]
                }
            if entry.get("exercises"): lesson["exercises"] = entry["exercises"]
            if entry.get("uoe"): lesson["use_of_english"] = entry["uoe"]
            lesson["has_content"] = True
            added_new += 1
        if n in EXTRA and lesson.get("has_content"):
            existing = lesson.get("use_of_english", []) or []
            lesson["use_of_english"] = existing + EXTRA[n]
            extended += 1

path.write_text(json.dumps(course, ensure_ascii=False, indent=1), encoding="utf-8")
print(f"OK: C1 — added {added_new} new lessons, extended {extended} pilot lessons")
for lv in course["levels"]:
    filled = sum(1 for le in lv["lessons"] if le.get("has_content"))
    uoe = sum(len(le.get("use_of_english",[])) for le in lv["lessons"])
    print(f"  {lv['code']}: {filled}/20 lessons, {uoe} UoE (avg {uoe/20:.1f}/lesson)")
